    private void btncalcularActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btncalcularActionPerformed
    try {
    if (txtAltura.getText().isEmpty() || txtpeso.getText().isEmpty()) {
        javax.swing.JOptionPane.showMessageDialog(this,
                "Preencha todos os campos.");
        return;
    }

    double altura = Double.parseDouble(txtAltura.getText());
    double peso = Double.parseDouble(txtpeso.getText());

    double imc = models.IMC.calcular(peso, altura);
    String interpretacao = models.IMC.interpretar(imc);

    lblResultado.setText(String.format("%.2f", imc));
    lblinterpretaçao.setText(interpretacao);

} catch (NumberFormatException e) {
    javax.swing.JOptionPane.showMessageDialog(this,
            "Informe valores numéricos válidos.");
}

    }//GEN-LAST:event_btncalcularActionPerformed

